import React, { useState } from 'react';
import { Search, Menu, User as UserIcon, MapPin, ArrowLeft, PlusCircle, ShoppingCart } from 'lucide-react';
import { UserRole, User } from '../types';

interface HeaderProps {
  user: User | null;
  onLoginClick: () => void;
  onLogoutClick: () => void;
  onMenuClick: () => void;
  onAdminClick: () => void;
  onVendorDashboardClick: () => void;
  locationText: string;
  onSearch: (query: string) => void;
  onHomeClick: () => void;
  onBackClick?: () => void;
  showBackButton?: boolean;
  onRegisterBusiness: () => void;
}

const Header: React.FC<HeaderProps> = ({ 
    user, onLoginClick, onLogoutClick, onMenuClick, onAdminClick, onVendorDashboardClick,
    locationText, onSearch, onHomeClick, onBackClick, showBackButton, onRegisterBusiness
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const handleSearchSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSearch(searchQuery);
  };

  return (
    <header className="sticky top-0 z-50 bg-primary text-white shadow-md transition-all duration-300">
      <div className="container mx-auto px-4 py-3 flex items-center justify-between gap-4">

        {/* Left: Logo & Menu */}
        <div className="flex items-center gap-4">
            <button onClick={onMenuClick} className="lg:hidden p-1">
                <Menu className="w-6 h-6" />
            </button>

            {showBackButton && (
               <button onClick={onBackClick} className="p-1 hover:bg-white/10 rounded-full transition-colors">
                  <ArrowLeft className="w-6 h-6" />
               </button>
            )}

            <div className="flex flex-col cursor-pointer italic" onClick={onHomeClick}>
                <h1 className="text-2xl font-bold tracking-tight text-white leading-none">
                    Flipkart
                </h1>
                <span className="text-[10px] font-bold text-secondary tracking-wide flex items-center gap-0.5">
                    Explore <span className="text-white">Plus</span> <span className="text-secondary">✦</span>
                </span>
            </div>
        </div>

        {/* Center: Search Bar */}
        <form onSubmit={handleSearchSubmit} className="flex-1 max-w-2xl relative hidden md:block group">
          <input
            type="text"
            placeholder="Search for products, brands and more"
            className="w-full py-2.5 pl-4 pr-12 rounded-sm bg-white text-gray-800 placeholder-gray-500 focus:outline-none shadow-sm text-sm"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          <button type="submit" className="absolute inset-y-0 right-3 flex items-center">
             <Search className="h-5 w-5 text-primary" />
          </button>
        </form>

        {/* Right: Actions */}
        <div className="flex items-center gap-6">
          {user ? (
            <div className="relative group">
              <button className="flex items-center gap-1.5 font-bold hover:bg-white/10 px-3 py-1.5 rounded transition-all">
                <span className="text-sm">{user.name}</span>
              </button>
              <div className="absolute right-0 top-full mt-1 w-48 bg-white text-gray-800 shadow-2xl rounded-sm overflow-hidden hidden group-hover:block z-50 border border-gray-100">
                 <div className="flex flex-col">
                    {user.role === UserRole.ADMIN && (
                        <button onClick={onAdminClick} className="px-4 py-3 hover:bg-gray-50 text-left text-sm font-medium border-b flex items-center gap-2 text-primary">Admin Panel</button>
                    )}
                    {user.role === UserRole.VENDOR && (
                        <button onClick={onVendorDashboardClick} className="px-4 py-3 hover:bg-gray-50 text-left text-sm font-medium border-b flex items-center gap-2">Dashboard</button>
                    )}
                    <button onClick={onLogoutClick} className="px-4 py-3 hover:bg-gray-50 text-left text-sm text-red-500">Logout</button>
                 </div>
              </div>
            </div>
          ) : (
            <button 
                onClick={onLoginClick} 
                className="bg-white text-primary px-8 py-1.5 rounded-sm font-bold text-sm shadow hover:bg-gray-100 transition-all"
            >
              Login
            </button>
          )}

          <button onClick={onRegisterBusiness} className="hidden lg:flex items-center gap-1 font-bold text-sm">
             Become a Seller
          </button>

          <button className="hidden lg:flex items-center gap-1.5 font-bold text-sm">
             <ShoppingCart className="w-5 h-5" />
             Cart
          </button>
        </div>
      </div>

      {/* Mobile Search */}
      <div className="md:hidden px-4 pb-3">
        <form onSubmit={handleSearchSubmit} className="relative">
           <input 
             type="text" 
             placeholder="Search for products, brands and more" 
             className="w-full py-2 px-3 rounded-sm bg-white text-gray-800 placeholder-gray-500 focus:outline-none text-sm"
             value={searchQuery}
             onChange={(e) => setSearchQuery(e.target.value)}
           />
           <Search className="absolute right-3 top-2.5 h-4 w-4 text-gray-400" />
        </form>
      </div>
    </header>
  );
};

export default Header;

import React, { useState } from 'react';
import { ShoppingCart, User, Truck, Clock, CheckCircle, ChevronRight, Phone, Bike, Package, ShieldCheck, XCircle, Plus, Trash2, Layers, ChevronDown, ChevronUp, AlertCircle } from 'lucide-react';
import { Category, Vendor, Banner, Order, Rider } from '../types';

interface AdminPanelProps {
  categories: Category[];
  vendors: Vendor[];
  banners: Banner[];
  orders: Order[];
  riders: Rider[];
  onAssignRider: (orderId: string, riderId: string) => void;
  onApproveVendor: (id: string) => void;
  onApproveRider: (id: string) => void;
  onRemoveVendor: (id: string) => void;
  onAddCategory: (cat: Category) => void;
  onRemoveCategory: (id: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  categories, vendors, orders, riders, onAssignRider, onApproveVendor, onApproveRider, onRemoveVendor, onAddCategory, onRemoveCategory
}) => {
  const [activeTab, setActiveTab] = useState<'ORDERS' | 'VENDORS' | 'RIDERS' | 'APPROVALS' | 'CATEGORIES'>('APPROVALS');
  const [showAddCat, setShowAddCat] = useState(false);
  const [parentCatId, setParentCatId] = useState<string | null>(null);
  const [newCat, setNewCat] = useState<Partial<Category>>({ name: '', description: '', themeColor: '#2874f0' });
  const [expandedCats, setExpandedCats] = useState<Set<string>>(new Set());

  const pendingRiders = riders.filter(r => !r.isApproved);
  const pendingVendors = vendors.filter(v => !v.isApproved);
  const totalPending = pendingRiders.length + pendingVendors.length;

  const toggleExpand = (id: string) => {
    const next = new Set(expandedCats);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setExpandedCats(next);
  };

  const handleAddCat = () => {
    if (!newCat.name) return;
    const category: Category = {
      id: 'cat_' + Date.now(),
      name: newCat.name,
      description: newCat.description || '',
      themeColor: newCat.themeColor || '#2874f0',
      subCategories: [],
      parent_id: parentCatId || undefined
    };
    onAddCategory(category);
    setShowAddCat(false);
  };

  return (
    <div className="bg-white min-h-screen">
      <div className="bg-primary p-6 text-white shadow-md">
          <div className="flex justify-between items-center">
            <div>
                <h1 className="text-2xl font-bold flex items-center gap-2"><ShieldCheck className="w-8 h-8"/> Admin Portal</h1>
                <p className="text-white/70 text-sm">Control center for Vendors, Riders, and Marketplace Orders</p>
            </div>
          </div>
      </div>

      <div className="border-b flex overflow-x-auto no-scrollbar bg-white sticky top-0 z-10 shadow-sm">
        <button onClick={() => setActiveTab('APPROVALS')} className={`px-6 py-4 font-bold whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'APPROVALS' ? 'border-b-4 border-primary text-primary' : 'text-gray-500'}`}>
            <AlertCircle className="w-4 h-4"/> Approvals 
            {totalPending > 0 && <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full ml-1">{totalPending}</span>}
        </button>
        <button onClick={() => setActiveTab('ORDERS')} className={`px-6 py-4 font-bold whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'ORDERS' ? 'border-b-4 border-primary text-primary' : 'text-gray-500'}`}>
            <ShoppingCart className="w-4 h-4"/> Orders
        </button>
        <button onClick={() => setActiveTab('CATEGORIES')} className={`px-6 py-4 font-bold whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'CATEGORIES' ? 'border-b-4 border-primary text-primary' : 'text-gray-500'}`}>
            <Layers className="w-4 h-4"/> Categories
        </button>
        <button onClick={() => setActiveTab('VENDORS')} className={`px-6 py-4 font-bold whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'VENDORS' ? 'border-b-4 border-primary text-primary' : 'text-gray-500'}`}>
            <User className="w-4 h-4"/> Vendors
        </button>
        <button onClick={() => setActiveTab('RIDERS')} className={`px-6 py-4 font-bold whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'RIDERS' ? 'border-b-4 border-primary text-primary' : 'text-gray-500'}`}>
            <Bike className="w-4 h-4"/> Riders
        </button>
      </div>

      <div className="p-6">
        {activeTab === 'APPROVALS' && (
          <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
             {/* Pending Vendors */}
             <section>
                <h2 className="text-lg font-bold mb-4 flex items-center gap-2">Pending Vendor Registration ({pendingVendors.length})</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {pendingVendors.map(vendor => (
                    <div key={vendor.id} className="border rounded-lg p-4 bg-white shadow-sm flex gap-4">
                       <img src={vendor.imageUrl} className="w-20 h-20 object-cover rounded" />
                       <div className="flex-1">
                          <h3 className="font-bold text-gray-900">{vendor.name}</h3>
                          <p className="text-xs text-gray-500 mb-2">{vendor.description}</p>
                          <div className="flex gap-2">
                             <button onClick={() => onApproveVendor(vendor.id)} className="flex-1 bg-green-600 text-white text-xs font-bold py-2 rounded">Approve</button>
                             <button onClick={() => onRemoveVendor(vendor.id)} className="flex-1 bg-gray-100 text-gray-600 text-xs font-bold py-2 rounded">Reject</button>
                          </div>
                       </div>
                    </div>
                  ))}
                  {pendingVendors.length === 0 && <p className="text-sm text-gray-400 py-4">No pending vendors.</p>}
                </div>
             </section>

             {/* Pending Riders */}
             <section>
                <h2 className="text-lg font-bold mb-4 flex items-center gap-2">Pending Rider Enrollment ({pendingRiders.length})</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {pendingRiders.map(rider => (
                    <div key={rider.id} className="border rounded-lg p-4 bg-white shadow-sm">
                       <div className="flex justify-between items-start mb-4">
                          <div className="flex items-center gap-3">
                             <div className="p-2 bg-blue-50 text-blue-600 rounded-full"><Bike className="w-6 h-6" /></div>
                             <div>
                                <h3 className="font-bold">{rider.name}</h3>
                                <p className="text-xs text-gray-500">{rider.phone} • {rider.vehicleType}</p>
                             </div>
                          </div>
                          <span className="text-[10px] bg-yellow-100 text-yellow-800 px-2 py-1 rounded font-bold">AWAITING VERIFICATION</span>
                       </div>
                       <div className="flex gap-2">
                          <button onClick={() => onApproveRider(rider.id)} className="flex-1 bg-primary text-white text-xs font-bold py-2 rounded">Approve Partner</button>
                          <button className="flex-1 bg-gray-100 text-gray-600 text-xs font-bold py-2 rounded">Delete Application</button>
                       </div>
                    </div>
                  ))}
                  {pendingRiders.length === 0 && <p className="text-sm text-gray-400 py-4">No pending riders.</p>}
                </div>
             </section>
          </div>
        )}

        {/* Existing tabs follow similar patterns, ensure they use primary blue theme */}
        {activeTab === 'CATEGORIES' && (
          <div className="max-w-4xl mx-auto">
             <div className="flex justify-between items-center mb-6">
                <h2 className="text-lg font-bold">Service Hierarchy</h2>
                <button onClick={() => setShowAddCat(true)} className="bg-primary text-white px-4 py-2 rounded-sm text-sm font-bold">Add New Category</button>
             </div>
             {/* ... Category list code ... */}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserRole, Vendor, Category, Banner, Order, Rider, Product
} from './types';
import { 
  fetchCategories, fetchVendors, fetchBanners, fetchRiders, fetchAllOrders, assignRiderToOrder
} from './services/api';
import Header from './components/Header';
import Footer from './components/Footer';
import BannerCarousel from './components/BannerCarousel';
import AuthModal from './components/AuthModal';
import VendorDashboard from './components/VendorDashboard';
import RiderRegistration from './components/RiderRegistration';
import RiderDashboard from './components/RiderDashboard';
import CategoryView from './components/CategoryView';
import BottomNav from './components/BottomNav';
import SideMenu from './components/SideMenu';
import FeaturedService from './components/FeaturedService';
import DeliveryOrderModal from './components/DeliveryOrderModal';
import ContactModal from './components/ContactModal';
import MapVisualizer from './components/MapVisualizer';
import AdminPanel from './components/AdminPanel';
import VendorRegistration from './components/VendorRegistration';
import { Loader2, ShoppingBag, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'HOME' | 'CATEGORY' | 'ADMIN' | 'VENDOR_DASHBOARD' | 'RIDER_REG' | 'RIDER_DASHBOARD' | 'VENDOR_REG'>('HOME');
  const [user, setUser] = useState<User | null>(null);
  const [activeRider, setActiveRider] = useState<Rider | null>(null);
  const [isAuthOpen, setAuthOpen] = useState(false);
  const [authInitialMode, setAuthInitialMode] = useState<UserRole>(UserRole.USER);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);

  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [riders, setRiders] = useState<Rider[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [banners, setBanners] = useState<Banner[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedDeliveryVendor, setSelectedDeliveryVendor] = useState<Vendor | null>(null);
  const [selectedContactVendor, setSelectedContactVendor] = useState<Vendor | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        const [cats, vends, bans, rids, ords] = await Promise.all([
          fetchCategories(),
          fetchVendors(),
          fetchBanners(),
          fetchRiders(),
          fetchAllOrders()
        ]);
        setCategories(cats);
        setVendors(vends);
        setBanners(bans);
        setRiders(rids);
        setOrders(ords);
      } catch (err: any) {
        console.error("Data load failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleApproveVendor = (id: string) => {
    setVendors(prev => prev.map(v => v.id === id ? {...v, isApproved: true} : v));
  };

  const handleApproveRider = (id: string) => {
    setRiders(prev => prev.map(r => r.id === id ? {...r, isApproved: true, status: 'OFFLINE'} : r));
  };

  const handleCategoryClick = (category: Category) => {
    setActiveCategory(category);
    setView('CATEGORY');
    window.scrollTo(0,0);
  };

  const openLogin = (mode: UserRole = UserRole.USER) => {
    setAuthInitialMode(mode);
    setAuthOpen(true);
  };

  if (isLoading) {
      return (
          <div className="h-screen flex flex-col items-center justify-center bg-white">
              <img src="https://static-assets-web.flixcart.com/fk-p-linchpin-web/fk-cp-zion/img/flipkart-plus_8d85f4.png" className="w-24 mb-4 animate-pulse" alt="Loading" />
              <Loader2 className="w-8 h-8 text-primary animate-spin" />
          </div>
      );
  }

  const currentVendorProfile = user?.role === UserRole.VENDOR 
    ? (vendors.find(v => v.email === user.email) || vendors[0]) 
    : null;

  return (
    <div className="flex flex-col min-h-screen bg-flipBg">
      <SideMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)}
        user={user}
        onLogin={openLogin}
        onLogout={() => { setUser(null); setView('HOME'); }}
        onAdminClick={() => openLogin(UserRole.ADMIN)}
        onRiderClick={() => setView('RIDER_REG')}
        onVendorRegClick={() => setView('VENDOR_REG')}
      />
      <Header 
        user={user}
        onLoginClick={() => openLogin()}
        onLogoutClick={() => setUser(null)}
        onMenuClick={() => setIsMenuOpen(true)}
        onAdminClick={() => { setView('ADMIN'); }}
        onVendorDashboardClick={() => setView('VENDOR_DASHBOARD')}
        locationText="Dahanu, MH"
        onSearch={() => {}}
        onHomeClick={() => setView('HOME')}
        showBackButton={view !== 'HOME'}
        onBackClick={() => setView('HOME')}
        onRegisterBusiness={() => setView('VENDOR_REG')}
      />

      {/* Category Scrolling Bar */}
      {view === 'HOME' && (
        <div className="bg-white shadow-theme border-b">
           <div className="container mx-auto flex items-center overflow-x-auto no-scrollbar py-3 px-4 gap-8">
              {categories.map(cat => (
                <button 
                  key={cat.id} 
                  onClick={() => handleCategoryClick(cat)}
                  className="flex flex-col items-center gap-1 shrink-0 group"
                >
                   <div className="w-16 h-16 rounded-full bg-gray-50 flex items-center justify-center p-2 group-hover:scale-110 transition-transform">
                      {/* Dynamic icons or images would go here */}
                      <span className="text-2xl">📦</span>
                   </div>
                   <span className="text-xs font-bold text-gray-800">{cat.name}</span>
                </button>
              ))}
           </div>
        </div>
      )}

      <main className="flex-1 pb-20">
        {view === 'HOME' && (
            <div className="container mx-auto p-4 space-y-4">
                <BannerCarousel banners={banners} />

                <section className="bg-white p-4 shadow-theme">
                  <div className="flex justify-between items-center mb-4">
                     <h2 className="text-xl font-bold">Featured Services</h2>
                     <button className="bg-primary text-white text-xs font-bold px-4 py-2 rounded-sm shadow">VIEW ALL</button>
                  </div>
                  <FeaturedService vendors={vendors.filter(v => v.isApproved)} onContactClick={(v) => setSelectedContactVendor(v)} onOrderClick={(v) => setSelectedDeliveryVendor(v)} />
                </section>

                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-3">
                   {vendors.filter(v => v.isApproved).map((v, i) => (
                      <div key={v.id} className="bg-white p-3 shadow-theme hover:shadow-lg transition cursor-pointer" onClick={() => handleCategoryClick(categories[0])}>
                         <div className="aspect-[3/2] bg-gray-100 mb-2 overflow-hidden">
                            <img src={v.imageUrl} className="w-full h-full object-cover" />
                         </div>
                         <h3 className="font-bold text-sm truncate">{v.name}</h3>
                         <div className="flex items-center gap-1 mt-1">
                            <span className="bg-green-600 text-white text-[10px] px-1 rounded font-bold flex items-center">4.5 ★</span>
                            <span className="text-gray-400 text-[10px] font-bold">(120)</span>
                         </div>
                         <p className="text-primary font-bold text-sm mt-1">From ₹{v.priceStart}</p>
                      </div>
                   ))}
                </div>
            </div>
        )}

        {view === 'CATEGORY' && activeCategory && (
            <CategoryView 
              category={activeCategory} onBack={() => setView('HOME')} 
              onSelectSubCategory={handleCategoryClick} vendors={vendors.filter(v => v.isApproved)} 
              userLocation={null} onContact={setSelectedContactVendor} onOrder={setSelectedDeliveryVendor} 
              onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
            />
        )}

        {view === 'ADMIN' && (
           <AdminPanel 
             categories={categories} vendors={vendors} banners={banners} orders={orders} riders={riders} 
             onAssignRider={() => {}} 
             onApproveVendor={handleApproveVendor}
             onApproveRider={handleApproveRider}
             onRemoveVendor={(id) => setVendors(prev => prev.filter(v => v.id !== id))}
             onAddCategory={(c) => setCategories(prev => [...prev, c])}
             onRemoveCategory={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
           />
        )}

        {view === 'VENDOR_REG' && (
            <div className="container mx-auto p-4">
                <VendorRegistration 
                    categories={categories} 
                    onSubmit={(v) => {
                      setVendors(prev => [...prev, {...v, isApproved: false} as Vendor]);
                      setView('HOME');
                    }} 
                    onCancel={() => setView('HOME')} 
                />
            </div>
        )}

        {view === 'VENDOR_DASHBOARD' && currentVendorProfile && (
            <VendorDashboard 
                vendor={currentVendorProfile} 
                orders={orders.filter(o => o.vendorId === currentVendorProfile.id)} 
                onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? {...o, status} : o))}
                onUpdateVendor={(updated) => setVendors(prev => prev.map(v => v.id === updated.id ? updated : v))}
            />
        )}

        {view === 'RIDER_REG' && (
            <RiderRegistration 
                onSubmit={(d) => { setRiders(prev => [...prev, {...d, isApproved: false} as Rider]); setView('HOME'); }} 
                onCancel={() => setView('HOME')} 
            />
        )}
      </main>

      <Footer />
      <BottomNav categories={categories} onCategoryClick={handleCategoryClick} />
      <AuthModal 
        isOpen={isAuthOpen} 
        onClose={() => setAuthOpen(false)} 
        initialMode={authInitialMode}
        onLoginSuccess={(email, role) => {
          setUser({ id: 'u' + Date.now(), name: email.split('@')[0], email, role: role as UserRole });
          if (role === UserRole.ADMIN) setView('ADMIN');
          else if (role === UserRole.VENDOR) setView('VENDOR_DASHBOARD');
      }} />

      {selectedDeliveryVendor && (
          <DeliveryOrderModal isOpen={!!selectedDeliveryVendor} onClose={() => setSelectedDeliveryVendor(null)} vendor={selectedDeliveryVendor} onPlaceOrder={() => {}} />
      )}

      {selectedContactVendor && (
          <ContactModal 
            vendor={selectedContactVendor} 
            onClose={() => setSelectedContactVendor(null)} 
            onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
          />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Search, Menu, User as UserIcon, MapPin, ArrowLeft, PlusCircle, ShoppingCart } from 'lucide-react';
import { UserRole, User } from '../types';

interface HeaderProps {
  user: User | null;
  onLoginClick: () => void;
  onLogoutClick: () => void;
  onMenuClick: () => void;
  onAdminClick: () => void;
  onVendorDashboardClick: () => void;
  locationText: string;
  onSearch: (query: string) => void;
  onHomeClick: () => void;
  onBackClick?: () => void;
  showBackButton?: boolean;
  onRegisterBusiness: () => void;
}

const Header: React.FC<HeaderProps> = ({ 
    user, onLoginClick, onLogoutClick, onMenuClick, onAdminClick, onVendorDashboardClick,
    locationText, onSearch, onHomeClick, onBackClick, showBackButton, onRegisterBusiness
}) => {
  const [searchQuery, setSearchQuery] = useState('');

  const handleSearchSubmit = (e: React.FormEvent) => {
