import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserRole, Vendor, Category, Banner, Order, Rider, Product
} from './types';
import { 
  fetchCategories, fetchVendors, fetchBanners, fetchRiders, fetchAllOrders, assignRiderToOrder
} from './services/api';
import Header from './components/Header';
import Footer from './components/Footer';
import BannerCarousel from './components/BannerCarousel';
import AuthModal from './components/AuthModal';
import VendorDashboard from './components/VendorDashboard';
import RiderRegistration from './components/RiderRegistration';
import RiderDashboard from './components/RiderDashboard';
import CategoryView from './components/CategoryView';
import BottomNav from './components/BottomNav';
import SideMenu from './components/SideMenu';
import FeaturedService from './components/FeaturedService';
import DeliveryOrderModal from './components/DeliveryOrderModal';
import ContactModal from './components/ContactModal';
import MapVisualizer from './components/MapVisualizer';
import AdminPanel from './components/AdminPanel';
import VendorRegistration from './components/VendorRegistration';
import EmergencyBar from './components/EmergencyBar';
import { Loader2, ShoppingBag, ChevronRight, Zap } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'HOME' | 'CATEGORY' | 'ADMIN' | 'VENDOR_DASHBOARD' | 'RIDER_REG' | 'RIDER_DASHBOARD' | 'VENDOR_REG'>('HOME');
  const [user, setUser] = useState<User | null>(null);
  const [isAuthOpen, setAuthOpen] = useState(false);
  const [authInitialMode, setAuthInitialMode] = useState<UserRole>(UserRole.USER);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);

  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [riders, setRiders] = useState<Rider[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [banners, setBanners] = useState<Banner[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedDeliveryVendor, setSelectedDeliveryVendor] = useState<Vendor | null>(null);
  const [selectedContactVendor, setSelectedContactVendor] = useState<Vendor | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        const [cats, vends, bans, rids, ords] = await Promise.all([
          fetchCategories(),
          fetchVendors(),
          fetchBanners(),
          fetchRiders(),
          fetchAllOrders()
        ]);
        setCategories(cats);
        setVendors(vends);
        setBanners(bans);
        setRiders(rids);
        setOrders(ords);
      } catch (err: any) {
        console.error("Data load failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleApproveVendor = (id: string) => {
    setVendors(prev => prev.map(v => v.id === id ? {...v, isApproved: true} : v));
  };

  const handleApproveRider = (id: string) => {
    setRiders(prev => prev.map(r => r.id === id ? {...r, isApproved: true, status: 'OFFLINE'} : r));
  };

  const handleCategoryClick = (category: Category) => {
    setActiveCategory(category);
    setView('CATEGORY');
    window.scrollTo(0,0);
  };

  const openLogin = (mode: UserRole = UserRole.USER) => {
    setAuthInitialMode(mode);
    setAuthOpen(true);
  };

  if (isLoading) {
      return (
          <div className="h-screen flex flex-col items-center justify-center bg-appBg">
              <div className="flex flex-col items-center gap-4">
                  <div className="text-5xl font-logo font-bold tracking-tighter text-primary lowercase animate-pulse">dahanu</div>
                  <Loader2 className="w-8 h-8 text-primary animate-spin" />
              </div>
          </div>
      );
  }

  const currentVendorProfile = user?.role === UserRole.VENDOR 
    ? (vendors.find(v => v.email === user.email) || vendors[0]) 
    : null;

  return (
    <div className="flex flex-col min-h-screen bg-appBg">
      <EmergencyBar onCategorySelect={(id) => {
          const cat = categories.find(c => c.id === id || c.subCategories?.some(s => s.id === id));
          if (cat) handleCategoryClick(cat);
      }} />
      <SideMenu 
        isOpen={isMenuOpen} 
        onClose={() => setIsMenuOpen(false)}
        user={user}
        onLogin={openLogin}
        onLogout={() => { setUser(null); setView('HOME'); }}
        onAdminClick={() => setView('ADMIN')}
        onRiderClick={() => setView('RIDER_REG')}
        onVendorRegClick={() => setView('VENDOR_REG')}
      />
      <Header 
        user={user}
        onLoginClick={() => openLogin()}
        onLogoutClick={() => setUser(null)}
        onMenuClick={() => setIsMenuOpen(true)}
        onAdminClick={() => { setView('ADMIN'); }}
        onVendorDashboardClick={() => setView('VENDOR_DASHBOARD')}
        locationText="Dahanu, Maharashtra"
        onSearch={() => {}}
        onHomeClick={() => setView('HOME')}
        showBackButton={view !== 'HOME'}
        onBackClick={() => setView('HOME')}
        onRegisterBusiness={() => setView('VENDOR_REG')}
      />

      <main className="flex-1 pb-24">
        {view === 'HOME' && (
            <div className="container mx-auto p-4 space-y-8">
                <BannerCarousel banners={banners} />

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    <div className="lg:col-span-2 space-y-8">
                        <section className="animate-fade-in">
                            <div className="flex justify-between items-center mb-6">
                                <h2 className="text-2xl font-black text-gray-900 flex items-center gap-2">
                                    <Zap className="w-6 h-6 text-secondary fill-secondary" />
                                    Featured Partner
                                </h2>
                            </div>
                            <FeaturedService 
                                vendors={vendors.filter(v => v.isApproved)} 
                                onContactClick={(v) => setSelectedContactVendor(v)} 
                                onOrderClick={(v) => setSelectedDeliveryVendor(v)} 
                            />
                        </section>

                        <section className="bg-white p-6 rounded-3xl shadow-xl border border-gray-100">
                             <h2 className="text-xl font-black text-gray-900 mb-6">Explore Services</h2>
                             <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
                                {categories.map(cat => (
                                    <button 
                                        key={cat.id} 
                                        onClick={() => handleCategoryClick(cat)}
                                        className="flex flex-col items-center p-4 rounded-2xl hover:bg-gray-50 transition-all group"
                                    >
                                        <div className="w-16 h-16 rounded-2xl bg-gray-50 flex items-center justify-center mb-3 group-hover:scale-110 transition-transform">
                                            <span className="text-2xl">📦</span>
                                        </div>
                                        <span className="text-xs font-bold text-gray-800 text-center">{cat.name}</span>
                                    </button>
                                ))}
                             </div>
                        </section>
                    </div>

                    <aside className="space-y-6">
                        <div className="bg-primary p-6 rounded-3xl shadow-2xl text-white relative overflow-hidden group">
                             <div className="relative z-10">
                                <h3 className="text-lg font-black mb-2">Join our network</h3>
                                <p className="text-white/70 text-sm mb-4">Start delivering or listing your business today and grow with us.</p>
                                <div className="flex flex-col gap-2">
                                    <button onClick={() => setView('RIDER_REG')} className="bg-white text-primary py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-gray-100 transition-colors">Become Rider</button>
                                    <button onClick={() => setView('VENDOR_REG')} className="bg-primary border border-white/20 text-white py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest hover:bg-white/10 transition-colors">Register Shop</button>
                                </div>
                             </div>
                        </div>
                    </aside>
                </div>
            </div>
        )}

        {view === 'CATEGORY' && activeCategory && (
            <CategoryView 
              category={activeCategory} onBack={() => setView('HOME')} 
              onSelectSubCategory={handleCategoryClick} vendors={vendors.filter(v => v.isApproved)} 
              userLocation={null} onContact={setSelectedContactVendor} onOrder={setSelectedDeliveryVendor} 
              onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
            />
        )}

        {view === 'ADMIN' && (
           <AdminPanel 
             categories={categories} vendors={vendors} banners={banners} orders={orders} riders={riders} 
             onAssignRider={() => {}} 
             onApproveVendor={handleApproveVendor}
             onApproveRider={handleApproveRider}
             onRemoveVendor={(id) => setVendors(prev => prev.filter(v => v.id !== id))}
             onAddCategory={(c) => setCategories(prev => [...prev, c])}
             onRemoveCategory={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
           />
        )}

        {view === 'VENDOR_REG' && (
            <div className="container mx-auto p-4">
                <VendorRegistration 
                    categories={categories} 
                    onSubmit={(v) => {
                      setVendors(prev => [...prev, {...v, isApproved: false} as Vendor]);
                      setView('HOME');
                    }} 
                    onCancel={() => setView('HOME')} 
                />
            </div>
        )}

        {view === 'VENDOR_DASHBOARD' && currentVendorProfile && (
            <VendorDashboard 
                vendor={currentVendorProfile} 
                orders={orders.filter(o => o.vendorId === currentVendorProfile.id)} 
                onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? {...o, status} : o))}
                onUpdateVendor={(updated) => setVendors(prev => prev.map(v => v.id === updated.id ? updated : v))}
            />
        )}

        {view === 'RIDER_REG' && (
            <RiderRegistration 
                onSubmit={(d) => { setRiders(prev => [...prev, {...d, isApproved: false} as Rider]); setView('HOME'); }} 
                onCancel={() => setView('HOME')} 
            />
        )}
      </main>

      <Footer />
      <BottomNav categories={categories} onCategoryClick={handleCategoryClick} />
      <AuthModal 
        isOpen={isAuthOpen} 
        onClose={() => setAuthOpen(false)} 
        initialMode={authInitialMode}
        onLoginSuccess={(email, role) => {
          setUser({ id: 'u' + Date.now(), name: email.split('@')[0], email, role: role as UserRole });
          if (role === UserRole.ADMIN) setView('ADMIN');
          else if (role === UserRole.VENDOR) setView('VENDOR_DASHBOARD');
      }} />

      {selectedDeliveryVendor && (
          <DeliveryOrderModal isOpen={!!selectedDeliveryVendor} onClose={() => setSelectedDeliveryVendor(null)} vendor={selectedDeliveryVendor} onPlaceOrder={() => {}} />
      )}

      {selectedContactVendor && (
          <ContactModal 
            vendor={selectedContactVendor} 
            onClose={() => setSelectedContactVendor(null)} 
            onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
          />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ShoppingCart, User, Truck, Clock, CheckCircle, ChevronRight, Phone, Bike, Package, ShieldCheck, XCircle, Plus, Trash2, Layers, ChevronDown, ChevronUp, AlertCircle } from 'lucide-react';
import { Category, Vendor, Banner, Order, Rider } from '../types';

interface AdminPanelProps {
  categories: Category[];
  vendors: Vendor[];
  banners: Banner[];
  orders: Order[];
  riders: Rider[];
  onAssignRider: (orderId: string, riderId: string) => void;
  onApproveVendor: (id: string) => void;
  onApproveRider: (id: string) => void;
  onRemoveVendor: (id: string) => void;
  onAddCategory: (cat: Category) => void;
  onRemoveCategory: (id: string) => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ 
  categories, vendors, orders, riders, onAssignRider, onApproveVendor, onApproveRider, onRemoveVendor, onAddCategory, onRemoveCategory
}) => {
  const [activeTab, setActiveTab] = useState<'ORDERS' | 'VENDORS' | 'RIDERS' | 'APPROVALS' | 'CATEGORIES'>('APPROVALS');
  const [expandedCats, setExpandedCats] = useState<Set<string>>(new Set());

  const pendingRiders = riders.filter(r => !r.isApproved);
  const pendingVendors = vendors.filter(v => !v.isApproved);
  const totalPending = pendingRiders.length + pendingVendors.length;

  return (
    <div className="bg-white min-h-screen">
      <div className="bg-primary p-8 text-white shadow-xl">
          <div className="flex justify-between items-center">
            <div>
                <h1 className="text-3xl font-black flex items-center gap-3"><ShieldCheck className="w-10 h-10"/> Administrative Portal</h1>
                <p className="text-white/70 text-sm mt-1">Global ecosystem control and partner management</p>
            </div>
          </div>
      </div>

      <div className="border-b flex overflow-x-auto no-scrollbar bg-white sticky top-0 z-10 shadow-sm">
        <button onClick={() => setActiveTab('APPROVALS')} className={`px-8 py-5 font-black text-xs uppercase tracking-widest whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'APPROVALS' ? 'border-b-4 border-primary text-primary' : 'text-gray-400 hover:text-gray-600'}`}>
            Approvals 
            {totalPending > 0 && <span className="bg-red-500 text-white text-[10px] px-2 py-0.5 rounded-full ml-1">{totalPending}</span>}
        </button>
        <button onClick={() => setActiveTab('ORDERS')} className={`px-8 py-5 font-black text-xs uppercase tracking-widest whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'ORDERS' ? 'border-b-4 border-primary text-primary' : 'text-gray-400 hover:text-gray-600'}`}>
            Marketplace Orders
        </button>
        <button onClick={() => setActiveTab('CATEGORIES')} className={`px-8 py-5 font-black text-xs uppercase tracking-widest whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'CATEGORIES' ? 'border-b-4 border-primary text-primary' : 'text-gray-400 hover:text-gray-600'}`}>
            Hierarchy
        </button>
        <button onClick={() => setActiveTab('VENDORS')} className={`px-8 py-5 font-black text-xs uppercase tracking-widest whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'VENDORS' ? 'border-b-4 border-primary text-primary' : 'text-gray-400 hover:text-gray-600'}`}>
            Vendors
        </button>
        <button onClick={() => setActiveTab('RIDERS')} className={`px-8 py-5 font-black text-xs uppercase tracking-widest whitespace-nowrap flex items-center gap-2 transition-all ${activeTab === 'RIDERS' ? 'border-b-4 border-primary text-primary' : 'text-gray-400 hover:text-gray-600'}`}>
            Rider Network
        </button>
      </div>

      <div className="p-8">
        {activeTab === 'APPROVALS' && (
          <div className="max-w-6xl mx-auto space-y-12 animate-fade-in">
             <section>
                <h2 className="text-xl font-black mb-6 flex items-center gap-2 text-gray-800">Pending Business Partners ({pendingVendors.length})</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {pendingVendors.map(vendor => (
                    <div key={vendor.id} className="border border-gray-100 rounded-3xl p-6 bg-white shadow-lg flex flex-col gap-4 group hover:-translate-y-1 transition-all">
                       <div className="flex gap-4">
                          <img src={vendor.imageUrl} className="w-16 h-16 object-cover rounded-2xl shadow-inner" />
                          <div className="flex-1 min-w-0">
                             <h3 className="font-bold text-gray-900 truncate">{vendor.name}</h3>
                             <p className="text-[10px] text-gray-400 uppercase font-black tracking-widest">{vendor.categoryIds[0]}</p>
                             <p className="text-xs text-gray-500 mt-1 line-clamp-2">{vendor.description}</p>
                          </div>
                       </div>
                       <div className="flex gap-2 mt-auto">
                          <button onClick={() => onApproveVendor(vendor.id)} className="flex-1 bg-green-600 text-white text-[10px] font-black uppercase tracking-widest py-3 rounded-xl shadow-lg shadow-green-100">Approve</button>
                          <button onClick={() => onRemoveVendor(vendor.id)} className="flex-1 bg-gray-50 text-gray-400 text-[10px] font-black uppercase tracking-widest py-3 rounded-xl hover:bg-red-50 hover:text-red-500 transition-colors">Reject</button>
                       </div>
                    </div>
                  ))}
                  {pendingVendors.length === 0 && <div className="col-span-full py-12 text-center text-gray-300 font-bold uppercase tracking-widest text-xs">No pending vendor applications.</div>}
                </div>
             </section>

             <section>
                <h2 className="text-xl font-black mb-6 flex items-center gap-2 text-gray-800">Pending Logistics Enrollment ({pendingRiders.length})</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {pendingRiders.map(rider => (
                    <div key={rider.id} className="border border-gray-100 rounded-3xl p-6 bg-white shadow-lg flex flex-col gap-4 group">
                       <div className="flex justify-between items-start">
                          <div className="flex items-center gap-4">
                             <div className="p-3 bg-primary/10 text-primary rounded-2xl"><Bike className="w-6 h-6" /></div>
                             <div>
                                <h3 className="font-bold text-gray-900">{rider.name}</h3>
                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{rider.vehicleType} • {rider.phone}</p>
                             </div>
                          </div>
                       </div>
                       <div className="flex gap-2 mt-auto">
                          <button onClick={() => onApproveRider(rider.id)} className="flex-1 bg-primary text-white text-[10px] font-black uppercase tracking-widest py-3 rounded-xl shadow-lg shadow-primary/20">Authorize Partner</button>
                          <button className="flex-1 bg-gray-50 text-gray-400 text-[10px] font-black uppercase tracking-widest py-3 rounded-xl">Discard</button>
                       </div>
                    </div>
                  ))}
                  {pendingRiders.length === 0 && <div className="col-span-full py-12 text-center text-gray-300 font-bold uppercase tracking-widest text-xs">No pending rider registrations.</div>}
                </div>
             </section>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

