import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserRole, Vendor, Category, Banner, Order, Rider, Product
} from './types';
import { 
  fetchCategories, fetchVendors, fetchBanners, fetchRiders, fetchAllOrders, assignRiderToOrder
} from './services/api';
import Header from './components/Header';
import Footer from './components/Footer';
import BannerCarousel from './components/BannerCarousel';
import AuthModal from './components/AuthModal';
import VendorDashboard from './components/VendorDashboard';
import RiderRegistration from './components/RiderRegistration';
import RiderDashboard from './components/RiderDashboard';
import CategoryView from './components/CategoryView';
import BottomNav from './components/BottomNav';
import SideMenu from './components/SideMenu';
import FeaturedService from './components/FeaturedService';
import DeliveryOrderModal from './components/DeliveryOrderModal';
import ContactModal from './components/ContactModal';
import AdminPanel from './components/AdminPanel';
import VendorRegistration from './components/VendorRegistration';
import EmergencyBar from './components/EmergencyBar';
import { Loader2, Zap, ChevronRight } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'HOME' | 'CATEGORY' | 'ADMIN' | 'VENDOR_DASHBOARD' | 'RIDER_REG' | 'RIDER_DASHBOARD' | 'VENDOR_REG'>('HOME');
  const [user, setUser] = useState<User | null>(null);
  const [isAuthOpen, setAuthOpen] = useState(false);
  const [authInitialMode, setAuthInitialMode] = useState<UserRole>(UserRole.USER);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | null>(null);

  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [riders, setRiders] = useState<Rider[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [banners, setBanners] = useState<Banner[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const [selectedDeliveryVendor, setSelectedDeliveryVendor] = useState<Vendor | null>(null);
  const [selectedContactVendor, setSelectedContactVendor] = useState<Vendor | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        const [cats, vends, bans, rids, ords] = await Promise.all([
          fetchCategories(),
          fetchVendors(),
          fetchBanners(),
          fetchRiders(),
          fetchAllOrders()
        ]);
        setCategories(cats);
        setVendors(vends);
        setBanners(bans);
        setRiders(rids);
        setOrders(ords);
      } catch (err: any) {
        console.error("Data load failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleApproveVendor = (id: string) => {
    setVendors(prev => prev.map(v => v.id === id ? {...v, isApproved: true} : v));
  };

  const handleApproveRider = (id: string) => {
    setRiders(prev => prev.map(r => r.id === id ? {...r, isApproved: true, status: 'OFFLINE'} : r));
  };

  const handleCategoryClick = (category: Category) => {
    setActiveCategory(category);
    setView('CATEGORY');
    window.scrollTo(0,0);
  };

  const openLogin = (mode: UserRole = UserRole.USER) => {
    setAuthInitialMode(mode);
    setAuthOpen(true);
  };

  if (isLoading) {
      return (
          <div className="h-screen flex flex-col items-center justify-center bg-white">
              <div className="flex flex-col items-center gap-4">
                  <h1 className="text-3xl font-bold italic text-primary">Flipkart</h1>
                  <Loader2 className="w-8 h-8 text-primary animate-spin" />
              </div>
          </div>
      );
  }

  const currentVendorProfile = user?.role === UserRole.VENDOR 
    ? (vendors.find(v => v.email === user.email) || vendors[0]) 
    : null;

  return (
    <div className="flex flex-col min-h-screen bg-appBg">
      <Header 
        user={user}
        onLoginClick={() => openLogin()}
        onLogoutClick={() => setUser(null)}
        onMenuClick={() => setIsMenuOpen(true)}
        onAdminClick={() => { setView('ADMIN'); }}
        onVendorDashboardClick={() => setView('VENDOR_DASHBOARD')}
        locationText="Dahanu, Maharashtra"
        onSearch={() => {}}
        onHomeClick={() => setView('HOME')}
        showBackButton={view !== 'HOME'}
        onBackClick={() => setView('HOME')}
        onRegisterBusiness={() => setView('VENDOR_REG')}
      />

      {/* Horizontal Category Bar - Flipkart Style */}
      {view === 'HOME' && (
        <div className="bg-white shadow-sm border-b">
           <div className="container mx-auto flex items-center overflow-x-auto no-scrollbar py-3 px-4 gap-12">
              {categories.map(cat => (
                <button 
                  key={cat.id} 
                  onClick={() => handleCategoryClick(cat)}
                  className="flex flex-col items-center gap-1 shrink-0 group transition-transform hover:scale-105"
                >
                   <div className="w-16 h-16 rounded-full bg-gray-50 flex items-center justify-center p-2">
                      <span className="text-2xl">📦</span>
                   </div>
                   <span className="text-xs font-bold text-gray-800">{cat.name}</span>
                </button>
              ))}
           </div>
        </div>
      )}

      <main className="flex-1 pb-24">
        {view === 'HOME' && (
            <div className="container mx-auto p-2 space-y-4">
                <BannerCarousel banners={banners} />

                <div className="bg-white p-4 shadow-sm rounded-sm">
                  <div className="flex justify-between items-center mb-4">
                      <h2 className="text-xl font-bold text-gray-900">Featured Services</h2>
                      <button className="bg-primary text-white text-xs font-bold px-4 py-2 rounded-sm shadow-sm">VIEW ALL</button>
                  </div>
                  <FeaturedService 
                      vendors={vendors.filter(v => v.isApproved)} 
                      onContactClick={(v) => setSelectedContactVendor(v)} 
                      onOrderClick={(v) => setSelectedDeliveryVendor(v)} 
                  />
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-2">
                   {vendors.filter(v => v.isApproved).map((v) => (
                      <div key={v.id} className="bg-white p-2 shadow-sm hover:shadow-md transition cursor-pointer flex flex-col items-center" onClick={() => setSelectedContactVendor(v)}>
                         <div className="aspect-square w-full bg-gray-100 mb-2 overflow-hidden">
                            <img src={v.imageUrl} className="w-full h-full object-cover" />
                         </div>
                         <h3 className="font-bold text-sm text-center line-clamp-1">{v.name}</h3>
                         <p className="text-primary font-bold text-sm mt-1">From ₹{v.priceStart}</p>
                         <p className="text-green-600 text-[10px] font-bold mt-0.5">Min. 40% Off</p>
                      </div>
                   ))}
                </div>
            </div>
        )}

        {view === 'CATEGORY' && activeCategory && (
            <CategoryView 
              category={activeCategory} onBack={() => setView('HOME')} 
              onSelectSubCategory={handleCategoryClick} vendors={vendors.filter(v => v.isApproved)} 
              userLocation={null} onContact={setSelectedContactVendor} onOrder={setSelectedDeliveryVendor} 
              onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
            />
        )}

        {view === 'ADMIN' && (
           <AdminPanel 
             categories={categories} vendors={vendors} banners={banners} orders={orders} riders={riders} 
             onAssignRider={() => {}} 
             onApproveVendor={handleApproveVendor}
             onApproveRider={handleApproveRider}
             onRemoveVendor={(id) => setVendors(prev => prev.filter(v => v.id !== id))}
             onAddCategory={(c) => setCategories(prev => [...prev, c])}
             onRemoveCategory={(id) => setCategories(prev => prev.filter(c => c.id !== id))}
           />
        )}

        {view === 'VENDOR_REG' && (
            <div className="container mx-auto p-4">
                <VendorRegistration 
                    categories={categories} 
                    onSubmit={(v) => {
                      setVendors(prev => [...prev, {...v, isApproved: false} as Vendor]);
                      setView('HOME');
                    }} 
                    onCancel={() => setView('HOME')} 
                />
            </div>
        )}

        {view === 'VENDOR_DASHBOARD' && currentVendorProfile && (
            <VendorDashboard 
                vendor={currentVendorProfile} 
                orders={orders.filter(o => o.vendorId === currentVendorProfile.id)} 
                onUpdateStatus={(id, status) => setOrders(prev => prev.map(o => o.id === id ? {...o, status} : o))}
                onUpdateVendor={(updated) => setVendors(prev => prev.map(v => v.id === updated.id ? updated : v))}
            />
        )}

        {view === 'RIDER_REG' && (
            <RiderRegistration 
                onSubmit={(d) => { setRiders(prev => [...prev, {...d, isApproved: false} as Rider]); setView('HOME'); }} 
                onCancel={() => setView('HOME')} 
            />
        )}
      </main>

      <Footer />
      <BottomNav categories={categories} onCategoryClick={handleCategoryClick} />
      <AuthModal 
        isOpen={isAuthOpen} 
        onClose={() => setAuthOpen(false)} 
        initialMode={authInitialMode}
        onLoginSuccess={(email, role) => {
          setUser({ id: 'u' + Date.now(), name: email.split('@')[0], email, role: role as UserRole });
          if (role === UserRole.ADMIN) setView('ADMIN');
          else if (role === UserRole.VENDOR) setView('VENDOR_DASHBOARD');
      }} />

      {selectedDeliveryVendor && (
          <DeliveryOrderModal isOpen={!!selectedDeliveryVendor} onClose={() => setSelectedDeliveryVendor(null)} vendor={selectedDeliveryVendor} onPlaceOrder={() => {}} />
      )}

      {selectedContactVendor && (
          <ContactModal 
            vendor={selectedContactVendor} 
            onClose={() => setSelectedContactVendor(null)} 
            onDirection={(v) => window.open(`https://www.google.com/maps/dir/?api=1&destination=${v.location.lat},${v.location.lng}`)}
          />
      )}
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { ChevronLeft, ChevronRight, PartyPopper, Stethoscope, Truck, Sparkles, Hammer, SprayCan, Utensils, Hotel, Calendar, Apple, ShoppingBasket } from 'lucide-react';
import { Category } from '../types';

interface BottomNavProps {
  categories: Category[];
  onCategoryClick: (category: Category) => void;
}

const BottomNav: React.FC<BottomNavProps> = ({ categories, onCategoryClick }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  const scroll = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
      const { current } = scrollRef;
      const scrollAmount = 200;
      if (direction === 'left') {
        current.scrollBy({ left: -scrollAmount, behavior: 'smooth' });
      } else {
        current.scrollBy({ left: scrollAmount, behavior: 'smooth' });
      }
    }
  };

  const getIcon = (iconName: string | undefined, color: string) => {
    const props = { className: "w-5 h-5 mb-1", style: { color } };
    switch(iconName) {
      case 'PartyPopper': return <PartyPopper {...props} />;
      case 'Stethoscope': return <Stethoscope {...props} />;
      case 'Truck': return <Truck {...props} />;
      case 'Sparkles': return <Sparkles {...props} />;
      case 'Hammer': return <Hammer {...props} />;
      case 'SprayCan': return <SprayCan {...props} />;
      case 'Utensils': return <Utensils {...props} />;
      case 'Hotel': return <Hotel {...props} />;
      case 'Apple': return <Apple {...props} />;
      case 'ShoppingBasket': return <ShoppingBasket {...props} />;
      default: return <Calendar {...props} />;
    }
  };

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-white shadow-[0_-2px_10px_rgba(0,0,0,0.1)] z-50 h-16 flex items-center border-t border-gray-100">
       <button onClick={() => scroll('left')} className="p-2 h-full bg-white hover:bg-gray-50 z-10 hidden md:flex items-center justify-center border-r">
         <ChevronLeft className="w-5 h-5 text-gray-600" />
       </button>

       <div 
         ref={scrollRef}
         className="flex-1 flex items-center overflow-x-auto gap-1 px-2 no-scrollbar h-full"
       >
          {categories.map(cat => (
             <button 
                key={cat.id} 
                onClick={() => onCategoryClick(cat)}
                className="flex flex-col items-center justify-center min-w-[70px] h-full hover:bg-gray-50 transition-all group"
             >
                <div 
                  className="transition-transform group-hover:-translate-y-0.5"
                >
                   {getIcon(cat.icon, '#2874f0')}
                </div>
                <span className="text-[10px] font-bold text-center leading-tight truncate w-full px-1 text-gray-700">
                    {cat.name}
                </span>
             </button>
          ))}
       </div>

       <button onClick={() => scroll('right')} className="p-2 h-full bg-white hover:bg-gray-50 z-10 hidden md:flex items-center justify-center border-l">
         <ChevronRight className="w-5 h-5 text-gray-600" />
       </button>
    </div>
  );
}

export default BottomNav;

