import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Store the confirmation result and verifier globally to manage lifecycle
let confirmationResult: ConfirmationResult | null = null;
let recaptchaVerifier: RecaptchaVerifier | null = null;

/**
 * Requests an OTP from Firebase.
 * @param phoneNumber The user's phone number (with country code).
 * @param containerId The ID of the HTML element for Recaptcha.
 */
export const requestOtp = async (
  phoneNumber: string, 
  containerId: string = 'recaptcha-container'
): Promise<{ success: boolean; message: string }> => {
  try {
    // 1. Setup/Reset Recaptcha singleton
    if (!recaptchaVerifier) {
      recaptchaVerifier = new RecaptchaVerifier(auth, containerId, {
        size: 'invisible',
        callback: () => {
          // reCAPTCHA solved, allow signInWithPhoneNumber.
        },
        'expired-callback': () => {
          // Response expired. Ask user to solve reCAPTCHA again.
          if (recaptchaVerifier) recaptchaVerifier.clear();
          recaptchaVerifier = null;
        }
      });
    }

    // 2. Format Phone Number (India Default +91)
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 3. Send SMS
    confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Error:', error);

    // Clear verifier on error so it can be re-initialized
    if (recaptchaVerifier) {
      try { recaptchaVerifier.clear(); } catch(e) {}
      recaptchaVerifier = null;
    }

    let errorMessage = 'Failed to send OTP.';
    if (error.code === 'auth/unauthorized-domain') {
      errorMessage = 'Domain not authorized. Add this URL to Firebase Console > Authentication > Settings > Authorized Domains.';
    } else if (error.code === 'auth/invalid-phone-number') {
      errorMessage = 'Invalid phone number format.';
    } else if (error.code === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Please try again later.';
    } else if (error.code === 'auth/internal-error') {
      errorMessage = 'Firebase Internal Error. Ensure "Phone" provider is enabled in Firebase Console.';
    }

    return { 
      success: false, 
      message: errorMessage 
    };
  }
};

/**
 * Verifies the OTP entered by the user.
 * @param otp The 6-digit code from SMS.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!confirmationResult) {
      return { success: false, message: 'No active session. Please enter your mobile number again.' };
    }

    const result = await confirmationResult.confirm(otp);
    const user = result.user;

    return { 
      success: true, 
      user, 
      message: 'Verification Successful' 
    };
  } catch (error: any) {
    console.error('OTP Verification Error:', error);
    let msg = 'Invalid OTP code. Please check and try again.';
    if (error.code === 'auth/code-expired') msg = 'OTP expired. Please request a new one.';

    return { success: false, message: msg };
  }
};

