// Store state globally
let confirmationResult: ConfirmationResult | null = null;
let recaptchaVerifier: RecaptchaVerifier | null = null;

/**
 * Resets the Recaptcha widget to prevent "internal-error" on retries.
 */
export const resetAuthContext = () => {
  if (recaptchaVerifier) {
    try {
      recaptchaVerifier.clear();
    } catch (e) {
      console.warn("Error clearing recaptcha:", e);
    }
    recaptchaVerifier = null;
  }
  confirmationResult = null;
};

/**
 * Requests an OTP from Firebase.
 */
export const requestOtp = async (
  phoneNumber: string, 
  containerId: string = 'recaptcha-container'
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    // Reset any previous state
    resetAuthContext();

    // 1. Setup Recaptcha
    const el = document.getElementById(containerId);
    if (!el) {
       return { success: false, message: 'CRITICAL: recaptcha-container missing in HTML.', code: 'missing-container' };
    }

    recaptchaVerifier = new RecaptchaVerifier(auth, containerId, {
      size: 'invisible',
      callback: () => {
        // reCAPTCHA solved
      },
      'expired-callback': () => {
        resetAuthContext();
      }
    });

    // 2. Format Phone Number (India +91)
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 3. Send SMS
    confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Exception:', error);

    const errorCode = error.code || '';
    let errorMessage = 'Failed to send OTP.';

    if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = 'UNAUTHORIZED DOMAIN: Go to Firebase Console > Auth > Settings > Authorized Domains and add ' + window.location.hostname;
    } else if (errorCode === 'auth/internal-error') {
      errorMessage = 'INTERNAL ERROR: Usually means Phone Auth is NOT ENABLED in Firebase Console Sign-in methods.';
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Wait a few minutes and try again.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'The phone number provided is incorrect.';
    }

    // Always reset on error
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage,
      code: errorCode
    };
  }
};

/**
 * Verifies the entered OTP.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!confirmationResult) {
      return { success: false, message: 'Session expired. Please request a new OTP.' };
    }

    const result = await confirmationResult.confirm(otp);
    const user = result.user;

    return { 
      success: true, 
      user, 
      message: 'Verification Successful' 
    };
  } catch (error: any) {
    console.error('OTP Verification Exception:', error);
    let msg = 'Invalid code. Please try again.';
    if (error.code === 'auth/code-expired') msg = 'OTP expired. Please try again.';

    return { success: false, message: msg };
  }
};

