import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Global state to track auth objects
let confirmationResult: ConfirmationResult | null = null;
let recaptchaVerifier: RecaptchaVerifier | null = null;

/**
 * Completely clears the Recaptcha and Auth state to prevent "Internal Errors" 
 * that occur when Firebase tries to re-use or re-initialize a widget on the same DOM element.
 */
export const resetAuthContext = () => {
  if (recaptchaVerifier) {
    try {
      recaptchaVerifier.clear();
      // Also clear the container HTML to be 100% sure
      const container = document.getElementById('recaptcha-container');
      if (container) container.innerHTML = '';
    } catch (e) {
      console.warn("Cleanup warning:", e);
    }
    recaptchaVerifier = null;
  }
  confirmationResult = null;
};

/**
 * Initiates the OTP flow.
 */
export const requestOtp = async (
  phoneNumber: string, 
  containerId: string = 'recaptcha-container'
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    // 1. Force a clean start
    resetAuthContext();

    // 2. Setup standard invisible Recaptcha
    recaptchaVerifier = new RecaptchaVerifier(auth, containerId, {
      size: 'invisible',
      callback: () => {
        // Solved
      },
      'expired-callback': () => {
        resetAuthContext();
      }
    });

    // 3. Format (India Default +91)
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 4. Send request to Firebase
    confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Exception:', error);

    const errorCode = error.code || '';
    let errorMessage = 'Failed to send OTP.';

    // Map common setup errors to helpful messages
    if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = `The domain "${window.location.hostname}" is not authorized. Add it in Firebase Console > Auth > Settings.`;
    } else if (errorCode === 'auth/internal-error') {
      errorMessage = 'Firebase Internal Error: This almost always means the "Phone" provider is NOT ENABLED in your Firebase Console.';
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Please try again after some time.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'Please enter a valid 10-digit mobile number.';
    }

    // Clean up immediately if there's an error
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage,
      code: errorCode
    };
  }
};

/**
 * Validates the SMS code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!confirmationResult) {
      return { success: false, message: 'Your session has expired. Please try again.' };
    }

    const result = await confirmationResult.confirm(otp);
    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('OTP Verification Error:', error);
    let msg = 'The code you entered is incorrect.';
    if (error.code === 'auth/code-expired') msg = 'The OTP has expired.';

    return { success: false, message: msg };
  }
};

