import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Global state to track auth objects
let confirmationResult: ConfirmationResult | null = null;
let recaptchaVerifier: RecaptchaVerifier | null = null;

/**
 * Resets the reCAPTCHA widget and auth state.
 * This is crucial to prevent "internal-error" caused by multiple initializations
 * or stale widgets in the DOM.
 */
export const resetAuthContext = () => {
  try {
    if (recaptchaVerifier) {
      recaptchaVerifier.clear();
      recaptchaVerifier = null;
    }
    const container = document.getElementById('recaptcha-container');
    if (container) {
      container.innerHTML = '';
    }
  } catch (e) {
    console.warn("Auth Context Reset Warning:", e);
  }
  confirmationResult = null;
};

/**
 * Requests an OTP from Firebase.
 */
export const requestOtp = async (
  phoneNumber: string, 
  containerId: string = 'recaptcha-container'
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    // 1. Ensure we start fresh
    resetAuthContext();

    // 2. Validate Container
    const el = document.getElementById(containerId);
    if (!el) {
      return { 
        success: false, 
        message: 'Auth container missing. Please refresh the page.', 
        code: 'missing-container' 
      };
    }

    // 3. Initialize Verifier
    // Note: We use the 'invisible' size to avoid UI clutter
    recaptchaVerifier = new RecaptchaVerifier(auth, containerId, {
      size: 'invisible',
      callback: () => {
        // reCAPTCHA solved
      },
      'expired-callback': () => {
        resetAuthContext();
      }
    });

    // 4. Trigger Render (Optional but helps catch errors early)
    await recaptchaVerifier.render();

    // 5. Format Number
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 6. Request SMS
    confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Request Error:', error);

    const errorCode = error.code || '';
    let errorMessage = 'Failed to send OTP.';

    // Detailed mapping for internal/configuration errors
    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Firebase Configuration Error: Ensure "Phone" provider is enabled and your domain is authorized in the Firebase Console.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = `The domain "${window.location.hostname}" is not authorized. Add it to "Authorized Domains" in Firebase Auth Settings.`;
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Please wait a few minutes before trying again.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'The phone number format is invalid. Use a 10-digit mobile number.';
    } else if (errorCode === 'auth/network-request-failed') {
      errorMessage = 'Network error. Please check your internet connection.';
    }

    // Always cleanup on failure
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!confirmationResult) {
      return { success: false, message: 'No active session. Please enter your phone number again.' };
    }

    const result = await confirmationResult.confirm(otp);
    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('Firebase OTP Verification Error:', error);
    let msg = 'Invalid OTP code. Please check and try again.';
    if (error.code === 'auth/code-expired') msg = 'OTP expired. Please request a new one.';
    return { success: false, message: msg };
  }
};

