import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Global references to prevent double-init
let confirmationResult: ConfirmationResult | null = null;
let recaptchaVerifier: RecaptchaVerifier | null = null;

/**
 * Cleanly destroys the reCAPTCHA instance.
 */
export const resetAuthContext = () => {
  try {
    if (recaptchaVerifier) {
      recaptchaVerifier.clear();
      recaptchaVerifier = null;
    }
    // Deep clean the container
    const container = document.getElementById('recaptcha-container');
    if (container) {
      container.innerHTML = '';
      // Create a fresh child for the next init
      const inner = document.createElement('div');
      inner.id = 'recaptcha-inner';
      container.appendChild(inner);
    }
  } catch (e) {
    console.warn("Auth Cleanup Warning:", e);
  }
  confirmationResult = null;
};

/**
 * Requests an OTP from Firebase.
 */
export const requestOtp = async (
  phoneNumber: string
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    // 1. Reset state
    resetAuthContext();

    // 2. Setup Verifier on the 'inner' div we just created
    // Use 'recaptcha-inner' to ensure we aren't clashing with previous renders
    recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-inner', {
      size: 'invisible',
      'callback': (response: any) => {
        // reCAPTCHA solved
      },
      'expired-callback': () => {
        resetAuthContext();
      }
    });

    // 3. Explicitly render
    await recaptchaVerifier.render();

    // 4. Format Number
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 5. Send SMS
    confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Request Error:', error);

    const errorCode = error.code || '';
    let errorMessage = 'An internal error occurred.';

    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Firebase Configuration Error: Please check if "Phone" provider is enabled in Firebase Console and your domain is authorized.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = `The domain ${window.location.hostname} is not authorized in Firebase Console.`;
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many requests. Try again later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'Invalid phone number format.';
    }

    // Always cleanup on failure to allow a retry
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!confirmationResult) {
      return { success: false, message: 'Session expired. Please re-enter your mobile number.' };
    }

    const result = await confirmationResult.confirm(otp);
    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('Firebase OTP Verification Error:', error);
    return { success: false, message: 'Invalid OTP. Please try again.' };
  }
};

