    let errorMessage = 'Failed to send OTP.';

    // Specific error handling for the common "internal-error"
    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Configuration Error: Please check if "Phone" provider is enabled in Firebase Console AND if your current domain is added to "Authorized Domains" in Firebase Auth Settings.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = 'This domain is not authorized. Add it to Firebase Console > Authentication > Settings > Authorized domains.';
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Please try again later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'Invalid phone number format. Please check the number.';
    }

    // Always reset on failure to allow retry
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!window.confirmationResult) {
      return { success: false, message: 'No active verification session. Please request a new OTP.' };
    }

    const result = await window.confirmationResult.confirm(otp);

    // Cleanup after success
    resetAuthContext();

    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('Firebase OTP Verification Error:', error);
    let msg = 'Invalid OTP. Please try again.';
    if (error.code === 'auth/code-expired') msg = 'OTP expired. Please request a new one.';
    return { success: false, message: msg };
  }
};

import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Use window object to store the verifier to ensure it persists correctly
declare global {
  interface Window {
    recaptchaVerifier: RecaptchaVerifier | undefined;
    confirmationResult: ConfirmationResult | undefined;
  }
}

/**
 * Resets the reCAPTCHA verifier instance and clears the DOM container.
 */
export const resetAuthContext = () => {
  try {
    if (window.recaptchaVerifier) {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    }

    const container = document.getElementById('recaptcha-container');
    if (container) {
      container.innerHTML = '<div id="recaptcha-inner"></div>';
    }
  } catch (e) {
    console.warn("Cleanup error:", e);
  }

  window.confirmationResult = undefined;
};

/**
 * Requests an OTP from Firebase.
 */
export const requestOtp = async (
  phoneNumber: string
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    // 1. Reset state to ensure a clean slate
    resetAuthContext();

    // 2. Initialize the Verifier on the inner element
    // Using a nested div helps avoid issues where Firebase modifies the container directly
    window.recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-inner', {
      'size': 'invisible',
      'callback': () => {
        console.log("reCAPTCHA solved");
      },
      'expired-callback': () => {
        console.warn("reCAPTCHA expired");
        resetAuthContext();
      }
    });

    // 3. Explicitly render
    await window.recaptchaVerifier.render();

    // 4. Format Number (E.164 format is required: +[country code][number])
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // 5. Sign in
    window.confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, window.recaptchaVerifier);

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Request Error:', error);

    const errorCode = error.code || '';
    let errorMessage = 'Security check failed.';

    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Auth Service Error: This is usually caused by: 1. Phone Auth not enabled in Firebase Console. 2. Your current domain not being in "Authorized Domains". 3. App Check blocking the request.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = `The domain ${window.location.hostname} is not authorized in Firebase Console settings.`;
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Activity blocked due to unusual traffic. Please try later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'The phone number format is invalid.';
    } else if (errorCode === 'auth/captcha-check-failed') {
      errorMessage = 'CAPTCHA verification failed. Please refresh and try again.';
    }

    // Always reset on failure to allow immediate retry
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!window.confirmationResult) {
      return { success: false, message: 'Session expired. Please request a new OTP.' };
    }

    const result = await window.confirmationResult.confirm(otp);

    // Success cleanup
    resetAuthContext();

    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('Firebase OTP Verification Error:', error);
    let msg = 'Invalid code. Please try again.';
    if (error.code === 'auth/code-expired') msg = 'This code has expired. Request a new one.';
    if (error.code === 'auth/invalid-verification-code') msg = 'Incorrect OTP entered.';
    return { success: false, message: msg };
  }
};

