    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-fade-in font-sans">
      <div className="bg-white w-full h-full md:h-auto md:max-w-4xl md:min-h-[620px] md:rounded-3xl shadow-2xl overflow-hidden flex flex-col md:flex-row relative">

        {/* Troubleshooting Overlay for Internal Errors */}
        {(errorInfo?.code === 'auth/internal-error' || errorInfo?.code === 'auth/unauthorized-domain' || errorInfo?.code === 'auth/configuration-not-found') && (
          <div className="absolute inset-0 bg-white z-[200] p-6 md:p-12 flex flex-col animate-fade-in overflow-y-auto no-scrollbar">
             <div className="max-w-2xl mx-auto w-full flex flex-col items-center">
                <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-6">
                   <Settings className="w-10 h-10 text-red-600 animate-pulse" />
                </div>

                <h3 className="text-2xl font-black text-gray-900 text-center mb-4">Firebase Configuration Required</h3>

                <div className="bg-red-50 p-6 rounded-2xl border border-red-100 mb-8 w-full">
                    <div className="flex items-center gap-3 mb-2">
                       <AlertCircle className="w-5 h-5 text-red-600" />
                       <p className="text-sm font-black text-red-900 uppercase tracking-wider">Error Details</p>
                    </div>
                    <p className="text-sm text-red-700 font-medium leading-relaxed">
                      {errorInfo.message}
                    </p>
                </div>

                <div className="w-full space-y-6">
                    <h4 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] border-b pb-2">Mandatory Steps:</h4>

                    <div className="flex gap-4 items-start bg-gray-50 p-4 rounded-xl border border-gray-100">
                       <div className="w-8 h-8 rounded-full bg-primary text-white flex items-center justify-center text-xs font-bold shrink-0 shadow-md">1</div>
                       <div>
                          <p className="font-bold text-gray-900 text-sm">Enable Phone Authentication</p>
                          <p className="text-xs text-gray-500 mt-1">Go to Firebase Console > Build > Authentication > Sign-in method > Add "Phone" provider and enable it.</p>
                       </div>
                    </div>

                    <div className="flex gap-4 items-start bg-gray-50 p-4 rounded-xl border border-gray-100">
                       <div className="w-8 h-8 rounded-full bg-primary text-white flex items-center justify-center text-xs font-bold shrink-0 shadow-md">2</div>
                       <div>
                          <p className="font-bold text-gray-900 text-sm">Authorize Your Domain</p>
                          <p className="text-xs text-gray-500 mt-1">In Authentication > Settings > Authorized domains, add <code className="bg-white px-1 border rounded text-primary font-mono">{window.location.hostname}</code></p>
                       </div>
                    </div>
                </div>

                <div className="mt-12 flex flex-col md:flex-row gap-4 w-full">
                    <a 
                      href="https://console.firebase.google.com/" 
