import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Extend window for global storage of Firebase Auth objects
declare global {
  interface Window {
    recaptchaVerifier: RecaptchaVerifier | undefined;
    confirmationResult: ConfirmationResult | undefined;
  }
}

/**
 * Step 2-B: Initialize in JavaScript
 * You must set this up before you call the signInWithPhoneNumber function.
 */
export const setupVerifier = () => {
  // If verifier already exists, clear it to prevent "Configuration Error" or "Internal Error"
  if (window.recaptchaVerifier) {
    try {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    } catch (e) {
      console.warn("Error clearing verifier:", e);
    }
  }

  // Ensure the container is empty before initializing
  const container = document.getElementById('recaptcha-container');
  if (container) {
    container.innerHTML = '';
  }

  try {
    // Initialize the Verifier (Modular v10 syntax)
    window.recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-container', {
      'size': 'invisible',
      'callback': (response: any) => {
        // reCAPTCHA solved - will proceed with submit
        console.log("reCAPTCHA solved", response);
      }
    });
  } catch (error) {
    console.error("Error setting up RecaptchaVerifier:", error);
  }
};

/**
 * Step 3: Update the Sign-In Function
 */
export const requestOtp = async (
  phoneNumber: string
): Promise<{ success: boolean; message: string; code?: string }> => {
  // 1. Ensure verifier is ready
  setupVerifier();

  if (!window.recaptchaVerifier) {
    return { success: false, message: 'Failed to initialize reCAPTCHA.' };
  }

  const appVerifier = window.recaptchaVerifier;
  const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

  try {
    // 2. Pass the appVerifier as the third argument
    const confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, appVerifier);
    window.confirmationResult = confirmationResult;
    return { success: true, message: 'OTP Sent!' };
  } catch (error: any) {
    console.error("SMS Error:", error.message);

    const errorCode = error.code || '';
    let errorMessage = 'Security check failed.';

    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Internal Error: Ensure Phone Auth is enabled in Firebase Console and this domain is authorized.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = 'Unauthorized Domain: Add this URL to Firebase Console > Authentication > Settings > Authorized domains.';
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Please try again later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'Invalid phone number format.';
    }

    // Reset verifier on error to allow retry
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Helper to reset auth state
 */
export const resetAuthContext = () => {
  if (window.recaptchaVerifier) {
    try {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    } catch (e) {}
  }
  const container = document.getElementById('recaptcha-container');
  if (container) container.innerHTML = '';
  window.confirmationResult = undefined;
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!window.confirmationResult) {
      return { success: false, message: 'No active session. Please resend OTP.' };
    }

    const result = await window.confirmationResult.confirm(otp);
    resetAuthContext();
    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('OTP Verification Error:', error);
    return { success: false, message: 'Invalid OTP. Please try again.' };
  }
};

import React, { useState, useEffect } from 'react';
import { X, Loader2, ShieldCheck, ArrowRight, User as UserIcon, Building2, Apple, AlertCircle, ExternalLink, Settings, HelpCircle } from 'lucide-react';
import { requestOtp, verifyOtp, resetAuthContext } from '../services/otpService';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword, 
  updateProfile, 
  signInWithPopup 
} from "firebase/auth";
import { 
  auth, 
  googleProvider, 
  appleProvider, 
  microsoftProvider 
} from "../services/firebaseConfig";
import { UserRole } from '../types';

interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLoginSuccess: (email: string, role: UserRole, isNewUser: boolean) => void;
  initialMode?: UserRole;
}

const GoogleIcon = () => (
  <svg viewBox="0 0 24 24" className="w-5 h-5">
    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
  </svg>
);

const MicrosoftIcon = () => (
  <svg viewBox="0 0 23 23" className="w-5 h-5">
    <path fill="#f35325" d="M1 1h10v10H1z"/>
    <path fill="#81bc06" d="M12 1h10v10H12z"/>
    <path fill="#05a6f0" d="M1 12h10v10H1z"/>
    <path fill="#ffba08" d="M12 12h10v10H12z"/>
  </svg>
);

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose, onLoginSuccess, initialMode = UserRole.USER }) => {
  const [userRole, setUserRole] = useState<UserRole>(initialMode);
  const [authMethod, setAuthMethod] = useState<'MOBILE' | 'EMAIL'>('MOBILE');
  const [viewState, setViewState] = useState<'INPUT' | 'OTP'>('INPUT');
  const [isSignUp, setIsSignUp] = useState(false);

  const [name, setName] = useState('');
  const [mobile, setMobile] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [errorInfo, setErrorInfo] = useState<{message: string, code?: string} | null>(null);

  useEffect(() => {
    if (isOpen) {
      setUserRole(initialMode);
      setViewState('INPUT');
      setIsSignUp(false);
      setName('');
      setMobile('');
      setEmail('');
      setOtp('');
      setPassword('');
      setErrorInfo(null);
      resetAuthContext();
      if (initialMode === UserRole.ADMIN) {
        setAuthMethod('EMAIL');
      } else {
        setAuthMethod('MOBILE');
      }
    }
  }, [initialMode, isOpen]);

  if (!isOpen) return null;

  const handleAction = async () => {
    setIsLoading(true);
    setErrorInfo(null);
    try {
      if (authMethod === 'MOBILE') {
        if (viewState === 'INPUT') {
            if (!mobile || mobile.length < 10) {
              setErrorInfo({message: "Enter a valid 10-digit mobile number."});
              setIsLoading(false);
              return;
            }
            const result = await requestOtp(mobile);
            if (result.success) {
              setViewState('OTP');
            } else {
              setErrorInfo({message: result.message, code: result.code});
            }
        } else {
            const result = await verifyOtp(otp);
            if (result.success) {
                onLoginSuccess(result.user.phoneNumber || `${mobile}@phone.com`, userRole, true);
                onClose();
            } else {
                setErrorInfo({message: result.message});
            }
        }
      } 
      else if (authMethod === 'EMAIL') {
          if (isSignUp) {
              const userCred = await createUserWithEmailAndPassword(auth, email, password);
              if (name) await updateProfile(userCred.user, { displayName: name });
              onLoginSuccess(userCred.user.email!, userRole, true);
          } else {
              const userCred = await signInWithEmailAndPassword(auth, email, password);
              onLoginSuccess(userCred.user.email!, userRole, false);
          }
          onClose();
      }
    } catch (error: any) {
      console.error(error);
      setErrorInfo({message: error.message || "Authentication failed.", code: error.code});
