// Fix: Use standard modular imports for Firebase Auth
import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  type ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

// Extend window for global storage of Firebase Auth objects
declare global {
  interface Window {
    recaptchaVerifier: RecaptchaVerifier | undefined;
    confirmationResult: ConfirmationResult | undefined;
    grecaptcha: any;
  }
}

/**
 * Step 2-B: Initialize reCAPTCHA Verifier
 * This ensures the verifier is ready before triggering the SMS.
 */
export const setupVerifier = () => {
  // If verifier already exists, clear it to prevent duplicate instances
  if (window.recaptchaVerifier) {
    try {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    } catch (e) {
      console.warn("Error clearing existing verifier:", e);
    }
  }

  // Ensure the container is present and clean
  const container = document.getElementById('recaptcha-container');
  if (container) {
    container.innerHTML = '';
  } else {
    console.error("Critical: recaptcha-container element missing from DOM.");
    return;
  }

  try {
    // Step 2: Initialize in JavaScript using modular SDK pattern
    window.recaptchaVerifier = new RecaptchaVerifier(auth, 'recaptcha-container', {
      'size': 'invisible',
      'callback': (response: any) => {
        // reCAPTCHA solved
        console.log("reCAPTCHA solved successfully.");
      },
      'expired-callback': () => {
        // Response expired. Ask user to solve reCAPTCHA again.
        console.warn("reCAPTCHA expired. Resetting context.");
        resetAuthContext();
      }
    });
  } catch (error) {
    console.error("Failed to initialize RecaptchaVerifier:", error);
  }
};

/**
 * Step 3: Update the Sign-In Function
 * This triggers the SMS by passing the appVerifier.
 */
export const requestOtp = async (
  phoneNumber: string
): Promise<{ success: boolean; message: string; code?: string }> => {
  // 1. Ensure verifier is ready
  setupVerifier();

  if (!window.recaptchaVerifier) {
    return { success: false, message: 'Failed to initialize security check. Please refresh.' };
  }

  const appVerifier = window.recaptchaVerifier;
  const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

  // Optional: Execute enterprise action if configured
  if (window.grecaptcha?.enterprise) {
    try {
      await window.grecaptcha.enterprise.ready(async () => {
        await window.grecaptcha.enterprise.execute('6LfBlWYsAAAAAFKrJyA0BL3KZQVnps5ycYWyGU__', {action: 'LOGIN'});
      });
    } catch (e) {
      console.warn("Optional Enterprise execute failed, proceeding with standard verifier.", e);
    }
  }

  try {
    // Step 3: Pass the appVerifier (the reCAPTCHA) as the third argument.
    const confirmationResult = await signInWithPhoneNumber(auth, formattedPhone, appVerifier);
    window.confirmationResult = confirmationResult;
    return { success: true, message: 'OTP Sent!' };
  } catch (error: any) {
    console.error("SMS Error:", error.message);

    const errorCode = error.code || '';
    let errorMessage = 'Security check failed. Please try again.';

    // Specific error handling for common Phone Auth issues
    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Internal Error: This is usually caused by: 1. Phone Auth not enabled in Firebase Console. 2. Your domain not being in "Authorized Domains". 3. API Key restrictions.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = `Unauthorized Domain: The domain "${window.location.hostname}" is not authorized. Go to Firebase Console > Authentication > Settings > Authorized domains.`;
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Too many attempts. Activity blocked for security. Please try again later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'The phone number provided is invalid.';
    } else if (errorCode === 'auth/captcha-check-failed') {
      errorMessage = 'Security verification failed. Please try again.';
    }

    // Reset verifier on error to allow immediate retry
    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Resets the reCAPTCHA instance and cleans up the DOM.
 */
export const resetAuthContext = () => {
  if (window.recaptchaVerifier) {
    try {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    } catch (e) {}
  }
  const container = document.getElementById('recaptcha-container');
  if (container) {
    container.innerHTML = '';
  }
  window.confirmationResult = undefined;
};

/**
 * Confirms the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!window.confirmationResult) {
      return { success: false, message: 'No active session. Please resend the OTP.' };
    }

    const result = await window.confirmationResult.confirm(otp);

    // Cleanup on success
    resetAuthContext();

    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('OTP Verification Error:', error);
    let msg = 'Incorrect code. Please try again.';
    if (error.code === 'auth/code-expired') msg = 'This code has expired. Please request a new one.';
    if (error.code === 'auth/invalid-verification-code') msg = 'Invalid OTP entered.';
    return { success: false, message: msg };
  }
};

import { 
  RecaptchaVerifier, 
  signInWithPhoneNumber, 
  ConfirmationResult 
} from "firebase/auth";
import { auth } from "./firebaseConfig";

declare global {
  interface Window {
    recaptchaVerifier: RecaptchaVerifier | undefined;
    confirmationResult: ConfirmationResult | undefined;
  }
}

/**
 * Completely resets the reCAPTCHA DOM and instance.
 * Call this before every OTP request attempt.
 */
export const resetAuthContext = () => {
  if (window.recaptchaVerifier) {
    try {
      window.recaptchaVerifier.clear();
      window.recaptchaVerifier = undefined;
    } catch (e) {
      console.warn("Recaptcha cleanup error:", e);
    }
  }

  const container = document.getElementById('recaptcha-container');
  if (container) {
    container.innerHTML = '';
  }

  window.confirmationResult = undefined;
};

/**
 * Initializes the RecaptchaVerifier on the specified DOM element.
 */
const initVerifier = () => {
  const container = document.getElementById('recaptcha-container');
  if (!container) return null;

  try {
    // Create new verifier with the modular auth instance
    const verifier = new RecaptchaVerifier(auth, container, {
      'size': 'invisible',
      'callback': () => {
        console.log("reCAPTCHA solved");
      },
      'expired-callback': () => {
        console.warn("reCAPTCHA expired, resetting...");
        resetAuthContext();
      }
    });

    window.recaptchaVerifier = verifier;
    return verifier;
  } catch (error) {
    console.error("Verifier init failed:", error);
    return null;
  }
};

/**
 * Sends OTP to the provided phone number.
 */
export const requestOtp = async (
  phoneNumber: string
): Promise<{ success: boolean; message: string; code?: string }> => {
  try {
    resetAuthContext();

    const verifier = initVerifier();
    if (!verifier) {
      return { success: false, message: 'Security container not found.' };
    }

    // Ensure phone number is in international format
    const formattedPhone = phoneNumber.startsWith('+') ? phoneNumber : `+91${phoneNumber}`;

    // Modular call: auth, phone, and verifier
    const result = await signInWithPhoneNumber(auth, formattedPhone, verifier);
    window.confirmationResult = result;

    return { success: true, message: 'OTP sent successfully!' };
  } catch (error: any) {
    console.error('Firebase Auth Error:', error);

    const errorCode = error.code || '';
    let errorMessage = 'Failed to verify security check.';

    if (errorCode === 'auth/internal-error') {
      errorMessage = 'Auth Internal Error: Please ensure you are not using multiple Firebase versions and your domain is authorized.';
    } else if (errorCode === 'auth/unauthorized-domain') {
      errorMessage = 'Domain not authorized. Please check Firebase Console settings.';
    } else if (errorCode === 'auth/too-many-requests') {
      errorMessage = 'Activity blocked due to unusual traffic. Try again later.';
    } else if (errorCode === 'auth/invalid-phone-number') {
      errorMessage = 'Invalid phone number.';
    }

    resetAuthContext();

    return { 
      success: false, 
      message: errorMessage, 
      code: errorCode 
    };
  }
};

/**
 * Verifies the OTP code.
 */
export const verifyOtp = async (
  otp: string
): Promise<{ success: boolean; user?: any; message: string }> => {
  try {
    if (!window.confirmationResult) {
      return { success: false, message: 'Session expired. Please request a new OTP.' };
    }

    const result = await window.confirmationResult.confirm(otp);
    resetAuthContext();

    return { 
      success: true, 
      user: result.user, 
      message: 'Verified' 
    };
  } catch (error: any) {
    console.error('OTP Verification Error:', error);
    return { success: false, message: 'Invalid OTP code.' };
  }
};

